function initSearch(){const s=(r,n="")=>{const e=document.getElementById("nmo-search-status");e.textContent=r,e.className="nmo-status "+n},i=document.getElementById("nmo-search-btn"),c=document.getElementById("nmo-search-results");i.addEventListener("click",async()=>{const r=document.getElementById("nmo-search-query").value.trim();if(!r){s("введите название теста","err");return}s("ищу на обоих сайтах...","loading"),i.disabled=!0,c.style.display="none",c.innerHTML="";const n=[];try{const e=await fetchViaBackground("https://24forcare.com/search/?query="+encodeURIComponent(r));if(e&&!e.error&&e.text){const t=document.createElement("div");t.innerHTML=e.text,Array.from(t.querySelectorAll("a.item-name")).forEach(a=>{const o=a.getAttribute("href")||"",l=(a.textContent||"").trim();if(!o||!l)return;const d=o.startsWith("http")?o:"https://24forcare.com/"+o.replace(/^\//,"");n.push({source:"24forcare",title:l,url:d})})}}catch(e){console.error("24forcare search error:",e)}try{const e=await fetchViaBackground("https://rosmedicinfo.ru/",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:"do=search&subaction=search&story="+encodeURIComponent(r)});if(e&&!e.error&&e.text){const t=document.createElement("div");t.innerHTML=e.text,Array.from(t.querySelectorAll(".short__title a")).forEach(a=>{const o=a.getAttribute("href")||"",l=(a.textContent||"").trim();!o||!l||n.push({source:"rosmedicinfo",title:l,url:o})})}}catch(e){console.error("rosmedicinfo search error:",e)}if(i.disabled=!1,n.length===0){s("ничего не найдено :(","warn");return}s(`найдено ${n.length} результат(ов)`,"ok"),c.style.display="flex",n.forEach(e=>{const t=document.createElement("div");t.className="nmo-result-item",t.innerHTML=`
                <span class="nmo-result-src ${e.source==="24forcare"?"src-24":"src-ros"}">${e.source==="24forcare"?"24fc":"rosmed"}</span>
                <span class="nmo-result-title">${e.title}</span>
            `,t.addEventListener("click",()=>{document.getElementById("nmo-url").value=e.url,storageSet("customUrl",e.url),s(`выбрано • ${e.source}`,"ok"),c.style.display="none"}),c.appendChild(t)})}),document.getElementById("nmo-search-query").addEventListener("keydown",r=>{r.key==="Enter"&&(r.preventDefault(),i.click())})}
